    item: InventoryItem,
    onAddStock: () -> Unit,
    onReduceStock: () -> Unit,
    onDeleteItem: () -> Unit
) {
    var showDialog by remember { mutableStateOf(false) } // dialog state

    if (showDialog) {
        EditItemDialog(
