@Composable
fun EditItemDialog(
    item: InventoryItem,
    onConfirm: (InventoryItem) -> Unit,
    onCancel: () -> Unit
) {
    // maintain state for editable fields
    var stock by remember { mutableStateOf(item.stock) }
    var price by remember { mutableStateOf(item.price ?: 0.0) }

    AlertDialog(
        onDismissRequest = onCancel,
        title = { Text(text = "Edit Item") },
        text = {
            Column {
                TextField(
                    value = stock.toString(),
                    onValueChange = { newText ->
                        stock = newText.toIntOrNull() ?: item.stock
                    },
                    label = { Text("Stock") },
                    keyboardType = KeyboardType.Number
                )
                TextField(
                    value = price.toString(),
                    onValueChange = { newText ->
                        price = newText.toDoubleOrNull() ?: item.price ?: 0.0
                    },
                    label = { Text("Price") },
                    keyboardType = KeyboardType.Number
                )
            }
        },
        confirmButton = {
            Button(
                onClick = {
                    val updatedItem = item.copy(
                        stock = stock,
                        price = price
                    )
                    onConfirm(updatedItem)
                }
            ) {
                Text("Confirm")
            }
        },
        dismissButton = {
            Button(onClick = onCancel) {
                Text("Cancel")
            }
        }
    )
}
```

